import React, { useState } from "react";
import FloatingInput from "../component/FloatingInput";

export default function AdminCreateUser() {
  const [user, setUser] = useState({
    username: "",
    name: "",
    email: "",
    password: "",
    role: "Student",
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const BASE_URL = "http://localhost:8086";

  // ---------------- VALIDATION ----------------
  const validate = () => {
    const err = {};

    if (!user.username) err.username = "Username required";
    if (!user.name) err.name = "Name required";

    if (!user.email) {
      err.email = "Email required";
    } else if (user.role === "Student") {
      if (!/^[iI][tT]\d{8}@my\.sliit\.lk$/.test(user.email)) {
        err.email = "Student must use ITXXXXXXXX@my.sliit.lk";
      }
    }

    if (!user.password || user.password.length < 6) {
      err.password = "Password must be 6+ characters";
    }

    return err;
  };

  // ---------------- SUBMIT ----------------
  const handleSubmit = async () => {
    setError("");
    setSuccess("");

    const validationErrors = validate();

    if (Object.keys(validationErrors).length > 0) {
      setError(Object.values(validationErrors)[0]);
      return;
    }

    try {
      const res = await fetch(`${BASE_URL}/user/admin/create`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(user),
      });

      if (res.ok) {
        setSuccess("User created successfully 🎉");

        setUser({
          username: "",
          name: "",
          email: "",
          password: "",
          role: "Student",
        });
      } else {
        setError("Failed to create user");
      }
    } catch {
      setError("Server not responding");
    }
  };

  // ---------------- UI (GLOSSY UPDATED) ----------------
  return (
  <div className="w-[500px] mx-auto p-8 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl space-y-4">

    <h2 className="text-xl font-bold text-center text-white">
      Admin Create User
    </h2>

    {error && (
      <p className="text-red-300 text-center font-medium">{error}</p>
    )}

    {success && (
      <p className="text-green-300 text-center font-medium">{success}</p>
    )}

    {/* INPUTS */}
    <FloatingInput
      name="username"
      label="Username"
      value={user.username}
      onChange={(e) => setUser({ ...user, username: e.target.value })}
    />

    <FloatingInput
      name="name"
      label="Full Name"
      value={user.name}
      onChange={(e) => setUser({ ...user, name: e.target.value })}
    />

    <FloatingInput
      name="email"
      type="email"
      label="Email"
      value={user.email}
      onChange={(e) => setUser({ ...user, email: e.target.value })}
    />

    <FloatingInput
      name="password"
      type="password"
      label="Password"
      value={user.password}
      onChange={(e) => setUser({ ...user, password: e.target.value })}
    />

    {/* ROLE SELECT - FIXED GLASS STYLE */}
    <select
      className="w-full px-4 py-3 rounded-lg bg-white/10 border border-white/30 text-white backdrop-blur-md focus:outline-none"
      value={user.role}
      onChange={(e) => setUser({ ...user, role: e.target.value })}
    >
      <option value="Student">Student</option>
      <option value="Admin">Admin</option>
      <option value="Academic Panel">Academic Panel</option>
    </select>

    {/* BUTTON */}
    <button
      onClick={handleSubmit}
      className="w-full py-2 rounded-lg bg-white/30 hover:bg-white/40 text-white font-semibold transition"
    >
      Create User
    </button>
  </div>
);
}
